    const prompt = `
      Write a professional cover letter in ${language} for this job application.
      Resume: ${cv}
      Job Description: ${jobPosting}

      Constraint: Do NOT use the words "current", "currently", or "present" (e.g., do NOT say "In my current role" or "At present"). Instead, refer to the specific role title or company name.
    `;
    // Updated to gemini-3-pro-preview
    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: { coverLetter: { type: Type.STRING } }
            }
        }
    });
    return JSON.parse(response.text || "{}").coverLetter || "";
