import { JobData } from '../types';

export async function saveJobApplicationToNotion(
    jobData: JobData, 
    cvText: string, 
    coverLetter: string,
    notionKey: string,
    notionDbId: string
) {
    if (!notionKey || !notionDbId) {
        throw new Error("Notion API Key or Database ID is missing.");
    }

    // Construct the payload for Notion API
    // Note: This requires the database to have these specific properties.
    const payload = {
        parent: { database_id: notionDbId },
        properties: {
            "Company": {
                title: [
                    {
                        text: {
                            content: jobData.companyName || "Unknown Company"
                        }
                    }
                ]
            },
            "Position": {
                rich_text: [
                    {
                        text: {
                            content: jobData.position || "Unknown Position"
                        }
                    }
                ]
            },
            "Status": {
                select: {
                    name: "Applied"
                }
            },
            "Date": {
                date: {
                    start: new Date().toISOString().split('T')[0] // YYYY-MM-DD
                }
            },
            "Link": {
                url: jobData.referenceUrl !== "Empty" ? jobData.referenceUrl : null
            },
            "Salary": {
                rich_text: [
                    {
                        text: {
                            content: jobData.salary || ""
                        }
                    }
                ]
            },
            // Assuming the DB might have a 'Next Action' text field
            "Next Action": {
                 rich_text: [
                    {
                        text: {
                            content: jobData.nextAction || ""
                        }
                    }
                ]
            }
        },
        children: [
            {
                object: "block",
                type: "heading_2",
                heading_2: {
                    rich_text: [{ text: { content: "Job Description" } }]
                }
            },
            {
                object: "block",
                type: "paragraph",
                paragraph: {
                    rich_text: [{ text: { content: "Reference Link: " + (jobData.referenceUrl || "N/A") } }]
                }
            },
             {
                object: "block",
                type: "paragraph",
                paragraph: {
                    rich_text: [{ text: { content: jobData.companyDescription || "" } }]
                }
            },
            {
                object: "block",
                type: "heading_2",
                heading_2: {
                    rich_text: [{ text: { content: "Cover Letter" } }]
                }
            },
            {
                object: "block",
                type: "paragraph",
                paragraph: {
                    rich_text: [{ text: { content: coverLetter ? coverLetter.substring(0, 2000) : "No cover letter generated." } }]
                }
            },
            {
                object: "block",
                type: "heading_2",
                heading_2: {
                    rich_text: [{ text: { content: "Tailored CV" } }]
                }
            },
             {
                object: "block",
                type: "paragraph",
                paragraph: {
                    rich_text: [{ text: { content: cvText ? cvText.substring(0, 2000) : "No CV generated." } }]
                }
            },
            // Note: Notion blocks have a 2000 character limit per block.
            // If the CV is longer, we might need to split it, but for now we truncate to avoid API errors.
             ...(cvText && cvText.length > 2000 ? [{
                 object: "block",
                 type: "paragraph",
                 paragraph: {
                     rich_text: [{ text: { content: cvText.substring(2000, 4000) } }]
                 }
             }] : [])
        ]
    };

    try {
        const response = await fetch('https://api.notion.com/v1/pages', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${notionKey}`,
                'Content-Type': 'application/json',
                'Notion-Version': '2022-06-28'
            },
            body: JSON.stringify(payload)
        });

        if (!response.ok) {
            const errorData = await response.json();
            throw new Error(`Notion API Error: ${errorData.message || response.statusText}`);
        }

        return await response.json();
    } catch (error: any) {
        // Notion API blocks CORS by default. 
        if (error.name === 'TypeError' && error.message === 'Failed to fetch') {
            throw new Error("CORS Error: The browser blocked the request to Notion. Use a proxy or backend.");
        }
        throw error;
    }
}

import React, { useState, useEffect } from 'react';
import CVTailor from './components/CVTailor';
import LiveConversation from './components/LiveConversation';
import ProfileBuilder from './components/ProfileBuilder';
import { BotIcon, EditIcon, FileStackIcon, SettingsIcon, DatabaseIcon, NotionIcon } from './components/icons';
import { initSupabase, HARDCODED_SUPABASE_URL } from './services/supabaseService';

type Tab = 'cv' | 'live' | 'profile';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('cv');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // Lazy initialization: Prefer hardcoded URL, otherwise read from localStorage.
  const [supabaseUrl, setSupabaseUrl] = useState(() => 
    HARDCODED_SUPABASE_URL || localStorage.getItem('supabase_url') || localStorage.getItem('supabaseUrl') || ''
  );
  const [supabaseKey, setSupabaseKey] = useState(() => 
    localStorage.getItem('supabase_key') || localStorage.getItem('supabaseKey') || ''
  );

  // Notion Settings
  const [notionKey, setNotionKey] = useState(() => localStorage.getItem('notion_key') || '');
  const [notionDbId, setNotionDbId] = useState(() => localStorage.getItem('notion_db_id') || '');

  const [isSupabaseConnected, setIsSupabaseConnected] = useState(false);

  useEffect(() => {
    // Attempt to initialize immediately on mount if keys are present in state
    if (supabaseUrl && supabaseKey) {
        const connected = initSupabase();
        setIsSupabaseConnected(connected);
    }
  }, []); // Only run once on mount

  const handleSaveSettings = () => {
    // Save Supabase Keys
    if (!supabaseUrl || !supabaseKey) {
        if (supabaseUrl || supabaseKey) {
             // If partial, do nothing? Or allow partial clearing?
             // Logic kept simple as per request.
        } else if (!window.confirm("You are about to save empty credentials. This will disconnect Supabase. Continue?")) {
            return;
        }
    }

    localStorage.setItem('supabase_url', supabaseUrl);
    localStorage.setItem('supabase_key', supabaseKey);

    // Save Notion Keys
    localStorage.setItem('notion_key', notionKey);
    localStorage.setItem('notion_db_id', notionDbId);

    // Initialize service
    const connected = initSupabase();
    setIsSupabaseConnected(connected);
    setIsSettingsOpen(false);
    alert('Settings saved!');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'cv':
        return <CVTailor />;
      case 'live':
        return <LiveConversation />;
      case 'profile':
        return <ProfileBuilder />;
      default:
        return null;
    }
  };

  const TabButton = ({ tab, label, icon }: { tab: Tab; label: string; icon: React.ReactNode }) => (
    <button
      onClick={() => setActiveTab(tab)}
      className={`flex items-center justify-center w-full px-4 py-3 text-sm font-medium transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-900 focus:ring-indigo-500 rounded-lg ${
        activeTab === tab
          ? 'bg-indigo-600 text-white shadow-lg'
          : 'bg-gray-800 text-gray-400 hover:bg-gray-700 hover:text-white'
      }`}
    >
      {icon}
      <span className="ml-2">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen bg-gray-900 text-gray-100 font-sans relative">
        {/* Settings Button */}
        <div className="absolute top-4 right-4 z-50">
            <button 
                onClick={() => setIsSettingsOpen(true)}
                className={`p-2 rounded-full transition-colors ${isSupabaseConnected ? 'bg-green-600/20 text-green-400' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}
                title="Application Settings"
            >
                <SettingsIcon />
            </button>
        </div>

        {/* Settings Modal */}
        {isSettingsOpen && (
            <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
                <div className="bg-gray-800 rounded-xl max-w-md w-full p-6 border border-gray-700 shadow-2xl max-h-[90vh] overflow-y-auto">
                    <div className="flex justify-between items-center mb-6">
                        <h2 className="text-xl font-bold flex items-center gap-2">
                            <SettingsIcon className="text-indigo-400" />
                            Settings
                        </h2>
                        <button onClick={() => setIsSettingsOpen(false)} className="text-gray-400 hover:text-white">&times;</button>
                    </div>

                    <div className="space-y-6">
                        {/* Supabase Section */}
                        <div className="space-y-3 pb-4 border-b border-gray-700">
                             <h3 className="font-semibold text-indigo-300 flex items-center gap-2">
                                <DatabaseIcon className="w-4 h-4" /> Supabase Connection
                             </h3>
                             <div>
                                <label className="block text-sm font-medium text-gray-400 mb-1">Project URL</label>
                                <input 
                                    type="text" 
                                    value={supabaseUrl} 
                                    onChange={(e) => setSupabaseUrl(e.target.value)}
                                    disabled={!!HARDCODED_SUPABASE_URL}
                                    placeholder="https://xyz.supabase.co"
                                    className={`w-full bg-gray-900 border border-gray-700 rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 ${!!HARDCODED_SUPABASE_URL ? 'text-gray-500 cursor-not-allowed' : ''}`}
                                />
                                {!!HARDCODED_SUPABASE_URL && <p className="text-xs text-green-500 mt-1">URL is hardcoded in code.</p>}
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-400 mb-1">Anon API Key</label>
                                <input 
                                    type="password" 
                                    value={supabaseKey} 
                                    onChange={(e) => setSupabaseKey(e.target.value)}
