                                <input 
                                    type="password" 
                                    value={notionKey} 
                                    onChange={(e) => setNotionKey(e.target.value)}
                                    placeholder="secret_..."
                                    className="w-full bg-gray-900 border border-gray-700 rounded-lg p-2 focus:ring-2 focus:ring-indigo-500"
                                />
                            </div>
