          <TabButton tab="cv" label="CV Tailor" icon={<EditIcon />} />
          <TabButton tab="live" label="Live Chat" icon={<BotIcon />} />
        </nav>

        <main>
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

