  const copyToClipboard = (text: string, type: string) => { 
    navigator.clipboard.writeText(text); 
    setToast({ message: `${type} copied to clipboard!`, type: 'success' });
  };
  const handleLoadClick = () => { fileInputRef.current?.click(); };

  const handleSaveAsTxt = (content: string, baseFilename: string) => {
    if (!content) return;

    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${baseFilename}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleSaveAsPdf = (content: string, baseFilename: string) => {
    if (!content || !window.jspdf) return;

    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();

    const margin = 15;
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const usableWidth = pageWidth - margin * 2;

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');

    const lines = doc.splitTextToSize(content, usableWidth);

    let cursorY = margin;
    const lineHeight = 7;

    lines.forEach((line: string) => {
        if (cursorY + lineHeight > pageHeight - margin) {
            doc.addPage();
            cursorY = margin;
        }
        doc.text(line, margin, cursorY);
        cursorY += lineHeight;
    });

    doc.save(`${baseFilename}.pdf`);
  };

  const handleInsightSubmit = async (queryOverride?: string) => {
