  }
}

export async function getTailoredCV(cv: string, jobPosting: string, language: string): Promise<{ tailoredCv: string; changesSummary: string; suggestedFilename: string; }> {
  try {
    const prompt = `
      You are an expert Executive Resume Writer.

      **CONTEXT:**
      - **Source Material:** The provided "Current CV/Profile" is a **Master Profile**. It is a comprehensive database containing the candidate's *entire* career history, every project, and every skill. It is intentionally too long.
      - **Target:** The "Job Description" is the specific role being applied for.

      **YOUR TASK:**
      Create a **targeted, high-impact CV** derived from the Master Profile that is laser-focused on the Job Description.

      **STRICT CONSTRAINTS:**
      1. **LENGTH LIMIT:** The output CV must be **MAXIMUM 2 PAGES** long. You MUST cut, summarize, or omit information to meet this limit.
      2. **CURATION:** Do NOT simply reformat the Master Profile. You must aggressively **FILTER** content.
         - Include ONLY experience and skills relevant to *this specific job*.
         - For older or irrelevant roles, reduce them to just Title, Company, and Dates, or omit them entirely if they add no value.
      3. **ACCURACY & TRUTH:** 
         - You must maintain the exact dates and company names from the source. 
         - **CRITICAL:** Do NOT include skills, technologies, or experiences from the 'Job Description' if they are NOT present in the 'Master Profile'. 
         - Do NOT claim the candidate has done things they haven't done just to match the job description.
         - If the JD requires a skill the candidate doesn't have, OMIT IT. Do not hallucinate it.
         - You MAY rephrase existing valid experience to use the keywords from the JD, but the underlying fact must remain true to the source.
      4. **LANGUAGE:** Write the output in **${language}**.

      **FORMATTING & STYLE (CRITICAL):**
      - **PLAIN TEXT ONLY**: Do NOT use Markdown formatting.
      - **NO MARKDOWN SYNTAX**: No bold (**), no italics (_), no hash-headers (#), no bullet points (* or - used as markdown). You may use simple dashes (-) for lists if needed for readability in plain text.
      - **LINKS**: Render links as "Label: https://url". Do NOT use [Label](URL) syntax.
      - **HEADERS**: Use ONLY these section headers in ALL CAPS: SUMMARY, EXPERIENCE, PROJECTS, SKILLS, EDUCATION. Do not use non-standard headers.
      - **NO PREAMBLE**: Start directly with the content. Do not say "Here is the CV".

      **TEMPORAL WORDING CONSTRAINT:**
      - Do not add or infer any status language that implies present-tense activity, continuity, or completion (e.g. "current", "ongoing", "active", "in progress", "completed").
      - Use only the explicit date ranges provided in the source material.
      - Do not introduce additional status qualifiers or temporal descriptors beyond those dates. Dates alone should be sufficient to convey timing.

      **INPUT DATA:**

      --- MASTER PROFILE (SOURCE) ---
      ${cv}

      --- JOB DESCRIPTION (TARGET) ---
      ${jobPosting}
    `;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    tailoredCv: { type: Type.STRING, description: "The tailored CV in PLAIN TEXT format (no markdown)." },
                    changesSummary: { type: Type.STRING, description: "A bulleted list explaining what was kept, what was cut, and why, to fit the 2-page limit." },
                    suggestedFilename: { type: Type.STRING, description: "Filename without extension (e.g. FirstName-LastName-Role-CV)" }
                }
            }
        }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    throw new Error("Failed to get tailored CV.");
  }
}

