import { JobData } from '../types';

export async function saveJobApplicationToNotion(
    jobData: JobData, 
    cvText: string, 
    coverLetter: string,
    notionKey: string,
    notionDbId: string
) {
    // Sanitize inputs
    const cleanKey = notionKey ? notionKey.trim().replace(/[^\x00-\x7F]/g, "") : "";
    const cleanDbId = notionDbId ? notionDbId.trim().replace(/[^\x00-\x7F]/g, "") : "";

    if (!cleanKey || !cleanDbId) {
        throw new Error("Notion API Key or Database ID is missing or invalid.");
    }

    // Construct the payload for Notion API
    // Note: This requires the database to have these specific properties.
    const payload = {
        parent: { database_id: cleanDbId },
        properties: {
            "Company": {
                title: [
                    {
                        text: {
                            content: jobData.companyName || "Unknown Company"
                        }
                    }
                ]
            },
            "Position": {
                rich_text: [
                    {
                        text: {
                            content: jobData.position || "Unknown Position"
                        }
                    }
                ]
            },
            "Status": {
                select: {
                    name: "Applied"
                }
            },
            "Date": {
                date: {
                    start: new Date().toISOString().split('T')[0] // YYYY-MM-DD
                }
            },
            "Link": {
                url: jobData.referenceUrl !== "Empty" ? jobData.referenceUrl : null
            },
            "Salary": {
                rich_text: [
                    {
                        text: {
                            content: jobData.salary || ""
                        }
                    }
                ]
            },
            // Assuming the DB might have a 'Next Action' text field
            "Next Action": {
                 rich_text: [
                    {
                        text: {
                            content: jobData.nextAction || ""
                        }
                    }
                ]
            }
        },
        children: [
            {
                object: "block",
                type: "heading_2",
                heading_2: {
                    rich_text: [{ text: { content: "Job Description" } }]
                }
            },
            {
                object: "block",
                type: "paragraph",
                paragraph: {
                    rich_text: [{ text: { content: "Reference Link: " + (jobData.referenceUrl || "N/A") } }]
                }
            },
             {
                object: "block",
                type: "paragraph",
                paragraph: {
                    rich_text: [{ text: { content: jobData.companyDescription || "" } }]
                }
            },
            {
                object: "block",
                type: "heading_2",
                heading_2: {
                    rich_text: [{ text: { content: "Cover Letter" } }]
                }
            },
            {
                object: "block",
                type: "paragraph",
                paragraph: {
                    rich_text: [{ text: { content: coverLetter ? coverLetter.substring(0, 2000) : "No cover letter generated." } }]
                }
            },
            {
                object: "block",
                type: "heading_2",
                heading_2: {
                    rich_text: [{ text: { content: "Tailored CV" } }]
                }
            },
             {
                object: "block",
                type: "paragraph",
                paragraph: {
                    rich_text: [{ text: { content: cvText ? cvText.substring(0, 2000) : "No CV generated." } }]
                }
            },
            // Note: Notion blocks have a 2000 character limit per block.
            // If the CV is longer, we might need to split it, but for now we truncate to avoid API errors.
             ...(cvText && cvText.length > 2000 ? [{
                 object: "block",
                 type: "paragraph",
                 paragraph: {
                     rich_text: [{ text: { content: cvText.substring(2000, 4000) } }]
                 }
             }] : [])
        ]
    };

    try {
        const response = await fetch('https://api.notion.com/v1/pages', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${cleanKey}`,
                'Content-Type': 'application/json',
                'Notion-Version': '2022-06-28'
            },
            body: JSON.stringify(payload)
        });

        if (!response.ok) {
            const errorData = await response.json();
            throw new Error(`Notion API Error: ${errorData.message || response.statusText}`);
        }

        return await response.json();
    } catch (error: any) {
        // Notion API blocks CORS by default. 
        if (error.name === 'TypeError' && error.message === 'Failed to fetch') {
            throw new Error("CORS Error: The browser blocked the request to Notion. Use a proxy or backend.");
        }
        throw error;
    }
}

import { GoogleGenAI, Type, LiveServerMessage, Modality } from "@google/genai";
import { ATSReport, JobData } from '../types';
import { fetchJobDescriptionFromEdge, isSupabaseConfigured } from './supabaseService';

// Ensure the API key is available, but do not hardcode it.
if (!process.env.API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean up text (e.g. replace literal \n with actual newlines)
function cleanText(text: string | undefined): string {
    if (!text) return "";
    return text.replace(/\\n/g, '\n').replace(/\\r/g, '').trim();
}

export async function processUrlForProfile(url: string): Promise<string> {
    try {
        let content = "";

        // 1. Try generic scraping first (if configured)
        if (isSupabaseConfigured()) {
            console.log("Attempting to fetch URL via Supabase Edge Function:", url);
            const edgeContent = await fetchJobDescriptionFromEdge(url);
            if (edgeContent && edgeContent.length > 100) {
                content = edgeContent;
            }
        }

        // 2. Fallback to Gemini Search if scraping failed or not configured
        if (!content) {
            console.log("Fetching URL via Gemini Search Grounding:", url);
            const prompt = `
                Retrieve the text content from this URL: ${url}
                Return the full visible text content of the page.
            `;
            const geminiResponse = await ai.models.generateContent({
                model: 'gemini-3-pro-preview',
                contents: prompt,
                config: {
                    tools: [{googleSearch: {}}],
                },
            });
            const text = geminiResponse.text;
            if (text && !text.startsWith("ERROR")) {
                content = text;
            }
        }

        if (!content) {
            throw new Error("Could not retrieve content from the provided URL.");
        }

        // 3. Summarize as a Project Entry
        const summaryPrompt = `
            You are a Career Architect building a Master Profile.

            SOURCE URL: ${url}
            SOURCE CONTENT:
            ${content.slice(0, 50000)}

            TASK:
            Analyze the source content (which is likely a GitHub repository, project page, or technical article).
            Create a concise "Project Entry" suitable for a CV/Portfolio.

            **FACTUAL ACCURACY IS CRITICAL:**
            - **STRICTLY** adhere to the technologies and features explicitly mentioned in the source content.
            - **DO NOT** infer or introduce related frameworks, even if the candidate has experience with them elsewhere or if they are commonly used together (e.g., do not add Redux just because React is present).
            - **DO NOT** mention technologies like LangChain, AWS, Azure, or specific libraries unless they are explicitly listed in the project's stack/README.
            - If the tech stack is not explicitly listed, list only what is undeniably visible in the code references or description.

            FORMAT:
            Project Name: [Name]
            URL: ${url}
            Tech Stack: [List ONLY technologies explicitly found in source]
            Summary: [3-4 sentence professional summary of functionality and your potential role/work]
            Key Features:
            - [Feature 1]
            - [Feature 2]

            Keep it professional, technical, and concise.
        `;

        const summaryResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: summaryPrompt,
        });

        return cleanText(summaryResponse.text);

    } catch (error) {
        console.error("Error processing URL for profile:", error);
        throw new Error("Failed to process URL. Ensure it is accessible.");
    }
}

export async function getJobDescriptionFromUrl(url: string): Promise<string> {
  // 1. Special handling for arbetsformedlingen.se (Public API)
  const arbetsformedlingenRegex = /arbetsformedlingen\.se\/platsbanken\/annonser\/(\d+)/;
  const match = url.match(arbetsformedlingenRegex);

  if (match && match[1]) {
    const jobId = match[1];
    const apiUrl = `https://platsbanken-api.arbetsformedlingen.se/jobs/v1/job/${jobId}`;
    try {
      console.log(`Fetching from Arbetsförmedlingen API: ${apiUrl}`);
      const response = await fetch(apiUrl, {
        headers: {
          'Accept': 'application/json',
          'INT_SYS': 'platsbanken_web_beta',
        }
      });

      if (!response.ok) {
        throw new Error(`API request failed with status ${response.status}`);
      }

      const data = await response.json();

      let description = "";
      if (data?.description?.text) {
          description = data.description.text;
      } else if (data?.description?.textFormatted) {
           const tempEl = document.createElement("div");
           tempEl.innerHTML = data.description.textFormatted;
           description = tempEl.innerText || tempEl.textContent || "";
      } else if (data?.body?.text) {
           const val = data.body.text;
           if (val && (val.includes('<p>') || val.includes('<br'))) {
               const tempEl = document.createElement("div");
               tempEl.innerHTML = val;
               description = tempEl.innerText || tempEl.textContent || "";
           } else {
               description = val;
           }
      }

      if (description && description.trim().length > 0) {
        return cleanText(description);
      } 
      // If we got data but couldn't find description field, try LLM extraction on the JSON
      try {
        const jsonString = JSON.stringify(data).slice(0, 30000);
        const extractPrompt = `
            Analyze the following JSON response from a job board API.
            Extract the main job description text. 
            Return ONLY the plain text of the job description.

            JSON Data:
            ${jsonString}
        `;

        const extractResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: extractPrompt,
        });

        const extractedText = (extractResponse.text || "").trim();
        if (extractedText && extractedText.length > 50) {
            return cleanText(extractedText);
        }
      } catch (fallbackError) {
        console.error("Gemini fallback extraction failed:", fallbackError);
      }
      throw new Error("Job description not found in the Arbetsförmedlingen API response.");
    } catch (apiError) {
      console.error("Error fetching from Arbetsförmedlingen API:", apiError);
      throw new Error("Failed to fetch job description from the Arbetsförmedlingen API.");
    }
  }

  // 2. Try Supabase Edge Function (Proxy/Scraper)
  // This bypasses CORS and can fetch the actual HTML content of the page.
  if (isSupabaseConfigured()) {
      try {
          console.log("Attempting to fetch via Supabase Edge Function...");
          const edgeContent = await fetchJobDescriptionFromEdge(url);

          if (edgeContent && edgeContent.length > 100) {
              console.log("Edge Function returned content. Length:", edgeContent.length);

              // Refine the raw scraped text with Gemini to extract just the Job Description
              const refinePrompt = `
                I have scraped the text from a job posting webpage. It contains navigation menus, footers, and other noise.

                YOUR TASK:
                Extract ONLY the **Job Description**, **Responsibilities**, and **Requirements/Qualifications**.
                Remove all navigation, headers, footers, and "Apply Now" buttons.

                SCRAPED TEXT:
                ${edgeContent.slice(0, 50000)} 
              `;

              const refineResponse = await ai.models.generateContent({
                  model: 'gemini-3-flash-preview',
                  contents: refinePrompt,
              });

              const refinedText = (refineResponse.text || "").trim();
              if (refinedText) return cleanText(refinedText);
          } else {
              console.log("Edge Function returned empty or too short content. Falling back to Search.");
          }
      } catch (edgeError) {
          console.error("Edge Function failed:", edgeError);
          // Fall through to method 3
      }
  }

  // 3. Fallback: Gemini Search Grounding
  // This relies on Google's search index. Good for older posts, bad for very new ones or non-indexed pages.
  try {
    if (!url.startsWith('http')) {
      throw new Error("Invalid URL provided.");
    }

    console.log("Falling back to Gemini Search Grounding...");
    const prompt = `
      Your task is to act as a simple but precise text extractor. You will be given a single URL.
      Your ONLY source of information MUST be the content at that exact URL: ${url}
      Extract and return ONLY the clean, plain text of that specific job description.

      STRICT CONSTRAINTS:
      - Output ONLY the job description text.
      - Do NOT add preambles like "Here is the job description" or "Based on the URL".
      - Do NOT include navigation menu text or footer links.

      If you cannot access the exact URL, respond with: "ERROR: Could not retrieve a job description from the provided URL."
    `;

    const geminiResponse = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          tools: [{googleSearch: {}}],
        },
    });

    const resultText = (geminiResponse.text || "").trim();

    if (resultText.startsWith("ERROR:") || !resultText) {
        const modelError = resultText.replace("ERROR: ", "");
        throw new Error(`${modelError || 'Could not retrieve a job description from the provided URL.'}`);
    }

    return cleanText(resultText);
  } catch (error) {
    console.error("Error getting job description from URL:", error);
    if (error instanceof Error) {
        if (error.message.includes('Could not retrieve a job description')) throw error;
        throw new Error(`Failed to process the URL: ${error.message}`);
    }
    throw new Error("An unknown error occurred while processing the job description URL.");
  }
}

